  ('medical-tech-moex-02576', 'medical-tech', 'medical-tech-moex-113-483fb9c7', 'sub-medical-tech-01', NULL, 'single_choice', '檢驗單位欲利用6 sigma策略進行品管，已知某檢驗項目總允許誤差（total allowable error, TEa）為 ± 30%，該單位在這項目的檢驗值與標準值有-6%的誤差（bias），且該檢驗項目的變異係數（CV）為 6%，則此 單位在這項目檢驗品質可達多少σ（sigma）？', '["6", "5", "4", "3"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:10+00:00", "source_pdf_sha1": "ef858d3c156f", "answer_pdf_sha1": "a2e0a0b3e8e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生物化學與臨床生化學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
